  "type" : "sedan",
  "make" : "Toyota",
  "description" : "Four-door sedan, lots of trunk space. Three to four passengers.",
  "warehouse" : [
    {
      "inventory" : 3,
      "color" : "red"
    }
  ]
}
{
  "_id" : 2,
  "type" : "coupe",
  "make" : "BMW",
  "description" : "Two-door convertible, driver's-side airbag.",
  "warehouse" : [
